function createSector(center, radius, startAngle, endAngle, color) {
  const positions = [center]
  const steps = 30

  for (let i = 0; i <= steps; i++) {
    const angle = startAngle + (endAngle - startAngle) * (i / steps)
    const point = Cesium.Cartesian3.fromDegrees(
      Cesium.Math.toDegrees(
        Cesium.Cartographic.fromCartesian(center).longitude + 
        Math.cos(angle) * radius / 111000
      ),
      Cesium.Math.toDegrees(
        Cesium.Cartographic.fromCartesian(center).latitude + 
        Math.sin(angle) * radius / 111000
      )
    )
    positions.push(point)
  }
  positions.push(center)

  return viewer.entities.add({
    polygon: {
      hierarchy: new Cesium.PolygonHierarchy(positions),
      material: color.withAlpha(0.3),
      outline: true,
      outlineColor: color,
      outlineWidth: 2
    }
  })
}

