function measureDistance(positions) {
  if (positions.length < 2) return 0

  let totalDistance = 0
  for (let i = 0; i < positions.length - 1; i++) {
    const start = positions[i]
    const end = positions[i + 1]

    const startCartographic = Cesium.Cartographic.fromCartesian(start)
    const endCartographic = Cesium.Cartographic.fromCartesian(end)

    const geodesic = new Cesium.EllipsoidGeodesic(
      startCartographic, endCartographic
    )
    totalDistance += geodesic.surfaceDistance
  }

  return totalDistance
}

