function calculatePolygonArea(positions) {
  const geometry = Cesium.PolygonGeometry.fromPositions({
    positions: positions,
    height: 0
  })

  const geometryInstance = new Cesium.GeometryInstance({
    geometry: geometry
  })

  const area = Cesium.PolygonGeometry.computeArea(
    geometryInstance.geometry
  )

  return area
}

// 或手动计算
function calculateAreaSimple(positions) {
  if (positions.length < 3) return 0

  const cartographics = positions.map(pos => 
    Cesium.Cartographic.fromCartesian(pos)
  )

  let area = 0
  const n = cartographics.length

  for (let i = 0; i < n; i++) {
    const j = (i + 1) % n
    const p1 = cartographics[i]
    const p2 = cartographics[j]

    area += p1.longitude * p2.latitude
    area -= p2.longitude * p1.latitude
  }

  area = Math.abs(area) / 2

  const avgLatitude = cartographics.reduce((sum, c) => 
    sum + c.latitude, 0) / n

  const metersPerDegreeLon = 111319 * Math.cos(avgLatitude)
  const metersPerDegreeLat = 110574

  return area * metersPerDegreeLon * metersPerDegreeLat
}

